"use strict";parserFactory.register("novelsrock.com",()=>new NovelsRockParser);class NovelsRockParser extends Parser{constructor(){super()}getChapterUrls(e){let r=[...e.querySelectorAll("li.wp-manga-chapter a")].filter(e=>null===e.querySelector("img")).map(e=>util.hyperLinkToChapter(e));return Promise.resolve(r.reverse())}findContent(e){let r=e.querySelector("div.read-container");return null===r?e.querySelector("div.reading-content"):r}extractTitleImpl(e){return e.querySelector("div.post-title h1")}extractAuthor(e){let r=e.querySelector("div.author-content");return null===r?super.extractAuthor(e):r.textContent}findChapterTitle(e){return e.querySelector("h1#chapter-heading")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.summary__content")]}}